SELECT [Reserv__Assign_ Link].[Reserv__Assign_ Type], [Reserv__Assign_ Link].[Sales Document No_] AS ordineNumero, [Reserv__Assign_ Link].[Sales Line No_] AS OrdineRiga, [Reserv__Assign_ Link].[TO Document No_], [Reserv__Assign_ Link].[TO Line No_], Val([Reserved_Assigned Quantity]) AS assortmentQty, [Reserv__Assign_ Link].Type, [Reserv__Assign_ Link].[Source Type], Val([Reserved_Assigned Quantity])*[assortmentquantity] AS pairsQty, "PREN-TRAS" AS statusRiga, [Reserv__Assign_ Link].[Selling Season Code] AS [Season Code], [Reserv__Assign_ Link].[Date Reservation], [Transfer Header].[Receipt Date] AS TransferReceiptDate, [Transfer Header].[Transfer-to Code] AS SourceLocation, [Sales Header].[Location Code] AS SalesLocation
FROM ((([Reserv__Assign_ Link] LEFT JOIN AssortimentiQuantita ON ([Reserv__Assign_ Link].[Assortment Code] = AssortimentiQuantita.[Assortment Code]) AND ([Reserv__Assign_ Link].[Assortment Variable Group] = AssortimentiQuantita.[Variable Group])) LEFT JOIN [Sales Header] ON [Reserv__Assign_ Link].[Sales Document No_] = [Sales Header].No_) LEFT JOIN [Transfer Line] ON ([Reserv__Assign_ Link].[TO Line No_] = [Transfer Line].[Line No_]) AND ([Reserv__Assign_ Link].[TO Document No_] = [Transfer Line].[Document No_])) LEFT JOIN [Transfer Header] ON [Transfer Line].[Document No_] = [Transfer Header].No_
WHERE ((([Reserv__Assign_ Link].[Reserv__Assign_ Type])=1) AND ((Val([Reserved_Assigned Quantity]))<>0) AND (([Reserv__Assign_ Link].Type)=20) AND (([Reserv__Assign_ Link].[Source Type])=5) AND (([Reserv__Assign_ Link].[Selling Season Code])=[forms]![principale]![filtroStagioneprenotazioni]));

